# 输入获取
cache = {}  # 记录每个url出现的次数
ans = []  # 记录题解


def sortURL(n):
    urlCount = list(cache.items())
    urlCount.sort(key=lambda x: (-x[1], x[0]))

    return ",".join(map(lambda x: x[0], urlCount[:n]))


while True:
    tmp = input()

    if tmp.isnumeric():  # 如果输入的是数字,则需要对前面输入的url进行排序统计
        print(sortURL(int(tmp)))
    else:
        if cache.get(tmp) is None:
            cache[tmp] = 1
        else:
            cache[tmp] += 1
